    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'ARS § 12-563', 'standard_text', 'Healthcare provider must use the same care, skill, and treatment that a reasonably prudent healthcare provider would use in the same or similar circumstances', 'key_elements', jsonb_build_array('Duty: provider-patient relationship established', 'Breach: care fell below applicable standard', 'Causation: breach was proximate cause of injury', 'Damages: actual compensable harm'), 'national_standard', 'Arizona uses a national standard of care (not locality rule) — what reasonably prudent provider anywhere would do in same circumstances', 'res_ipsa', 'Available in limited circumstances (e.g., instrument left in body, wrong limb operated on)', 'informed_consent', 'Separate actionable claim under ARS § 12-562; provider must disclose risks a reasonably prudent patient in that position would want to know', 'definition_providers', 'Medical malpractice providers include physicians, nurses, hospitals, nursing homes, and other licensed healthcare entities (ARS § 12-561)', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('ARS § 12-563', 'ARS § 12-561', 'ARS § 12-562', 'Justia — Arizona Medical Malpractice'), 'confidence', 'high')),
